import java.util.*;

public class GreedyVsDP {

    public int greedyCoins(int[] coins, int amount) {
        Arrays.sort(coins);
        int count = 0;
        for (int i = coins.length - 1; i >= 0 && amount > 0; i--)
            while (amount >= coins[i]) { amount -= coins[i]; count++; }
        return amount == 0 ? count : -1;
    }

    public int dpCoins(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1);
        dp[0] = 0;
        for (int a = 1; a <= amount; a++)
            for (int c : coins) if (c <= a && dp[a-c]+1 < dp[a]) dp[a] = dp[a-c]+1;
        return dp[amount] > amount ? -1 : dp[amount];
    }

    public static void main(String[] args) {
        GreedyVsDP gvd = new GreedyVsDP();
        // Non-canonical system: {1, 3, 4}, amount = 6
        // Greedy: 4+1+1 = 3 coins; DP: 3+3 = 2 coins
        int[] coins = {1, 3, 4};
        System.out.println("Coins {1,3,4} amount=6:");
        System.out.println("  Greedy: " + gvd.greedyCoins(coins, 6) + " coins");
        System.out.println("  DP:     " + gvd.dpCoins(coins, 6) + " coins");

        // Canonical: greedy and DP agree
        int[] usCoins = {1, 5, 10, 25};
        System.out.println("Coins {1,5,10,25} amount=30:");
        System.out.println("  Greedy: " + gvd.greedyCoins(usCoins, 30) + " coins");
        System.out.println("  DP:     " + gvd.dpCoins(usCoins, 30) + " coins");
    }
}

public class JumpGame {

    public boolean canJump(int[] nums) {
        int maxReach = 0;
        for (int i = 0; i < nums.length; i++) {
            if (i > maxReach) return false; // current position is unreachable
            // TODO: maxReach = Math.max(maxReach, i + nums[i])
        }
        return true;
    }

    public int minJumps(int[] nums) {
        // Greedy BFS-like: track current range and next range
        int jumps = 0, curEnd = 0, farthest = 0;
        for (int i = 0; i < nums.length - 1; i++) {
            farthest = Math.max(farthest, i + nums[i]);
            if (i == curEnd) {
                jumps++;
                curEnd = farthest;
                if (curEnd >= nums.length - 1) break;
            }
        }
        return jumps;
    }

    public static void main(String[] args) {
        JumpGame jg = new JumpGame();
        System.out.println("[2,3,1,1,4] can jump: " + jg.canJump(new int[]{2,3,1,1,4}));
        System.out.println("[3,2,1,0,4] can jump: " + jg.canJump(new int[]{3,2,1,0,4}));
        System.out.println("[2,3,1,1,4] min jumps: " + jg.minJumps(new int[]{2,3,1,1,4}));
        System.out.println("[2,3,0,1,4] min jumps: " + jg.minJumps(new int[]{2,3,0,1,4}));
    }
}
